@namespace sv_cdb3f198feb8442ab41bb77ed50a1f24.Components.Pages.JobApplication

<nav aria-label="Application steps" class="mb-4">
    <ol class="step-indicator d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var cssClass = step == CurrentStep ? "active"
                         : CompletedSteps.Contains(step) ? "completed"
                         : "pending";
            <li class="step-item @cssClass text-center flex-fill position-relative"
                role="button"
                @onclick="() => HandleClick(step)">
                <div class="step-circle mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center @(cssClass == "completed" ? "bg-success text-white" : cssClass == "active" ? "bg-primary text-white" : "bg-secondary text-white")"
                     style="width:36px;height:36px;font-size:0.85rem;">
                    @if (CompletedSteps.Contains(step))
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </div>
                <small class="@(cssClass == "pending" ? "text-muted" : "")">@StepNames[step]</small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@namespace sv_cdb3f198feb8442ab41bb77ed50a1f24.Components.Pages.JobApplication

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="mb-0">Position @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control" value="@Company" @onchange="e => { Company = (string?)e.Value ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control" value="@Title" @onchange="e => { Title = (string?)e.Value ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@StartDate.ToString("yyyy-MM-dd")" @onchange="HandleStartDateChange" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@(EndDate?.ToString("yyyy-MM-dd"))" disabled="@IsCurrent" @onchange="HandleEndDateChange" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" checked="@IsCurrent" @onchange="HandleCurrentChange" id="current-@Index" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Description" @onchange="e => { Description = (string?)e.Value ?? ""; NotifyChanged(); }"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime StartDate { get; set; } = DateTime.Today;
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryData> OnChanged { get; set; }

    private void HandleStartDateChange(ChangeEventArgs e)
    {
        if (DateTime.TryParse((string?)e.Value, out var d)) StartDate = d;
        NotifyChanged();
    }

    private void HandleEndDateChange(ChangeEventArgs e)
    {
        EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null;
        NotifyChanged();
    }

    private void HandleCurrentChange(ChangeEventArgs e)
    {
        IsCurrent = (bool)(e.Value ?? false);
        if (IsCurrent) EndDate = null;
        NotifyChanged();
    }

    private void NotifyChanged()
    {
        OnChanged.InvokeAsync(new WorkEntryData(Company, Title, StartDate, IsCurrent ? null : EndDate, Description));
    }

    public record WorkEntryData(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
}

