@namespace sv_cdb3f198feb8442ab41bb77ed50a1f24.Components.Pages.JobApplication

<h5 class="mb-3">Work History</h5>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var idx = i;
    var entry = Entries[idx];
    <WorkEntryEditor Index="@(idx + 1)"
                     Company="@entry.Company"
                     Title="@entry.Title"
                     StartDate="@entry.StartDate"
                     EndDate="@entry.EndDate"
                     IsCurrent="@(entry.EndDate is null && entry.Company != "")"
                     Description="@entry.Description"
                     ShowRemove="@(Entries.Count > 1)"
                     OnRemove="() => RemoveEntry(idx)"
                     OnChanged="data => UpdateEntry(idx, data)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryData> Entries { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryData>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryData("", "", DateTime.Today, null, ""));
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void UpdateEntry(int index, WorkEntryEditor.WorkEntryData data)
    {
        Entries[index] = new WorkEntryData(data.Company, data.Title, data.StartDate, data.EndDate, data.Description);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position requires at least a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }

    public record WorkEntryData(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
}

