@namespace sv_cdb3f198feb8442ab41bb77ed50a1f24.Components.Pages.JobApplication

<h5 class="mb-3">References</h5>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Refs.Count; i++)
{
    var idx = i;
    var r = Refs[idx];
    <ReferenceEditor Index="@(idx + 1)"
                     Name="@r.Name"
                     Relationship="@r.Relationship"
                     Email="@r.Email"
                     Phone="@r.Phone"
                     ShowRemove="@(Refs.Count > 2)"
                     OnRemove="() => RemoveRef(idx)"
                     OnChanged="data => UpdateRef(idx, data)" />
}

@if (Refs.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddRef">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<RefData> Refs { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<List<RefData>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddRef()
    {
        if (Refs.Count < 3)
            Refs.Add(new RefData("", "", "", ""));
    }

    private void RemoveRef(int index)
    {
        if (Refs.Count > 2)
            Refs.RemoveAt(index);
    }

    private void UpdateRef(int index, ReferenceEditor.ReferenceData data)
    {
        Refs[index] = new RefData(data.Name, data.Relationship, data.Email, data.Phone);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in Refs)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync(Refs);
    }

    public record RefData(string Name, string Relationship, string Email, string Phone);
}

