@namespace sv_cdb3f198feb8442ab41bb77ed50a1f24.Components.Pages.JobApplication

<h5 class="mb-3">Cover Letter</h5>

<div class="mb-3">
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync(CoverLetter ?? "");
    }
}

@namespace sv_cdb3f198feb8442ab41bb77ed50a1f24.Components.Pages.JobApplication
@using sv_cdb3f198feb8442ab41bb77ed50a1f24.Models

<h5 class="mb-4">Review Your Application</h5>

@if (Submitted)
{
    <div class="alert alert-success text-center py-4">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate.ToString("MMM yyyy") &ndash;
                        @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@(string.IsNullOrWhiteSpace(CoverLetter) ? "(none provided)" : CoverLetter)</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool isSubmitting;
    private bool Submitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        ErrorMessage = null;
        try
        {
            ApplicationId = await OnSubmit();
            Submitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

