                              ValidateEmail="AppService.ValidateEmailAsync"
                              OnNext="HandlePersonalNext" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="HandleWorkNext"
                             OnBack="GoBack" />
            break;

        case 2:
            <ReferencesStep Refs="references"
                            OnNext="HandleRefsNext"
                            OnBack="GoBack" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="GoBack" />
            break;

        case 4:
            <ReviewStep Personal="@BuildPersonalInfo()"
                        WorkEntries="@BuildWorkEntries()"
                        References="@BuildReferences()"
                        CoverLetter="@coverLetter"
                        OnEditSection="GoToStep"
                        OnBack="GoBack"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;
    private HashSet<int> completedSteps = [];

    // Step 1 state
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2 state
    private List<WorkHistoryStep.WorkEntryData> workEntries = [new("", "", DateTime.Today, null, "")];

    // Step 3 state
    private List<ReferencesStep.RefData> references = [new("", "", "", ""), new("", "", "", "")];

    // Step 4 state
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step <= currentStep || completedSteps.Contains(step))
            currentStep = step;
    }

    private void GoBack()
    {
        if (currentStep > 0) currentStep--;
    }

    private void HandlePersonalNext(PersonalInfoStep.PersonalInfoResult result)
    {
        fullName = result.FullName;
        email = result.Email;
        phone = result.Phone;
        address = result.Address;
        completedSteps.Add(0);
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkHistoryStep.WorkEntryData> entries)
    {
        workEntries = entries;
        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleRefsNext(List<ReferencesStep.RefData> refs)
    {
        references = refs;
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        completedSteps.Add(3);
        currentStep = 4;
    }

    private PersonalInfo BuildPersonalInfo() => new(fullName, email, phone, address);

    private List<WorkEntry> BuildWorkEntries() =>
        workEntries.Select(e => new WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList();

    private List<Reference> BuildReferences() =>
        references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            BuildPersonalInfo(),
            new WorkHistory(BuildWorkEntries()),
            BuildReferences(),
            coverLetter
        );
        return await AppService.SubmitApplicationAsync(application);
    }
}

